function L_total = totalDistance( ...
 f_vec,dishDia,elevation,guardInterval, ...
 disableLNAFilter,EIRPmax,BlockingDb,attenuation, ...
 Htx,Hrx,Imax ...
 )
 distanceINR = zeros(size(f_vec));
 distanceBlocking = zeros(size(f_vec));
 EarthRadius = 6371;
 for k = 1:length(f_vec)
 f = f_vec(k);
 lambda = 300/(f*1000);
 antennaGain = S465_gain(dishDia/lambda, elevation);
 filterAtt = fss_filter_gain(f*1000,guardInterval,attenuation,disableLNAFilter);
 L_target_BL = EIRPmax + antennaGain + filterAtt - BlockingDb;
 L_target_OOB = apply_spectral_mask(EIRPmax, f*1000) + antennaGain + filterAtt - Imax;
 F_BL = @(d) total_loss(d, f, Htx, Hrx, EarthRadius, 50) - L_target_BL;
 F_OOB = @(d) total_loss( d, f, Htx, Hrx, EarthRadius, 50) - L_target_OOB;

 try
 distanceBlocking(k) = fzero(F_BL,[1e-6 5000]);
 catch
 distanceBlocking(k) = 0;
 end

 try
 distanceINR(k) = fzero(F_OOB,[1e-6 5000]);
 catch
 distanceINR(k) = 0;
 end
 end
 L_total = max(distanceINR, distanceBlocking);
end

