function [azimuth, elevation] = satellite_angles(lat_rx, lon_rx, lat_sat, lon_sat, alt_sat)
 if nargin < 5 || isempty(alt_sat)
 alt_sat = 35786; % km
 end
 Re = 6371; % km
 lat_rx = deg2rad(lat_rx);
 lon_rx = deg2rad(lon_rx);

 lat_sat = deg2rad(lat_sat);
 lon_sat = deg2rad(lon_sat);
 rx = Re * [
 cos(lat_rx)*cos(lon_rx);
 cos(lat_rx)*sin(lon_rx);
 sin(lat_rx)];
 Rs = Re + alt_sat;
 sat = Rs * [
 cos(lat_sat)*cos(lon_sat);
 cos(lat_sat)*sin(lon_sat);
 sin(lat_sat)];
 los = sat - rx;
 east = [
 -sin(lon_rx);
 cos(lon_rx);
 0];
 north = [
 -sin(lat_rx)*cos(lon_rx);
 -sin(lat_rx)*sin(lon_rx);
 cos(lat_rx)];
 up = [
 cos(lat_rx)*cos(lon_rx);
 cos(lat_rx)*sin(lon_rx);
 sin(lat_rx)];
 e = dot(los,east);
 n = dot(los,north);
 u = dot(los,up);
 azimuth = atan2d(e,n);
 azimuth = mod(azimuth,360);
 elevation = atan2d(u,sqrt(e^2+n^2));
end

function [G, phi_min] = S465_gain(ratio_D_lambda, phi_deg)
 if ratio_D_lambda <= 0
 error('D/λ must be positivve');
 end
 if phi_deg < 0 || phi_deg > 180
 error('Angle phi must be in [0, 180] degrees.');
 end
 if ratio_D_lambda >= 50
 phi_min = max(1, 100 / ratio_D_lambda);
 else % ratio_D_lambda < 50
 if ratio_D_lambda < 33.3
 phi_min = 2.5;
 else
 phi_min = max(2, 114 * (ratio_D_lambda)^(-1.09));
 end
 end
 if phi_deg < phi_min
 error('phi (%.2f°) less than allowed phi_min = %.2f°.', phi_deg, phi_min);
 end
 if phi_deg < 48
 G = 32 - 25 * log10(phi_deg);
 else % phi_deg >= 48
 G = -10;
 end
end

function d_solution = solve_distance_from_loss(L_target, f, h_tx, h_rx,p_forest)
 E_R = 6371; 
 F = @(d) total_loss(d,f,h_tx,h_rx,E_R,p_forest) - L_target;
 d_solution = fzero(F, [0.0001, 8000]);
end

function x = norminv_plain(p)
 x = -sqrt(2)*erfcinv(2*p);
end

function horison = radioHorison(h_tx,h_rx,E_R) 
 k_refr = 1.33;
 d_tx = sqrt(2*E_R*h_tx/1000) * k_refr;
 d_rx = sqrt(2*E_R*h_rx/1000) * k_refr;
 horison = d_tx + d_rx;
end

function L = total_loss(d, f, h_tx, h_rx, E_R,p_forest)
 if(d <= 10^-2) L = -1; return; end
 k_refr = 1.33;
 gamma = 0.008;

 sigma_l = 4;
 sigma_s = 6;

 p_es = 3;
 p_ctt = p_forest;
 L_l = -2 .* log10( ...
 10.^(-5 .* log10(f) - 12.5) + ...
 10.^(-16.5));
 d_tx = sqrt(2*E_R*h_tx/1000) * k_refr;
 d_rx = sqrt(2*E_R*h_rx/1000) * k_refr;
 Qinv = norminv_plain(p_ctt/100);
 d_fs = sqrt(d.^2 + ((h_tx-h_rx)/1000).^2);
 L_bfsg = 92.4 + 20.*log10(f) + 20.*log10(d_fs) + gamma.*d_fs;
 L_s = 32.98 + 23.9.*log10(d) + 3.*log10(f);
 sigma_cb = sqrt( ...
 (sigma_l^2 .* 10.^(-0.2.*L_l) + ...
 sigma_s^2 .* 10.^(-0.2.*L_s)) ./ ...
 (10.^(-0.2.*L_l) + ...
 10.^(-0.2.*L_s)));
 L_ctt = -5 .* log10(10.^(-0.2.*L_l) + 10.^(-0.2.*L_s)) - sigma_cb .* Qinv;
 if(p_forest == 0) L_ctt = 0; end
 E_sp = 2.6 .* (1 - exp(-0.1*(d_tx+d_rx))) .* log10(p_es/50);
 L_diff = diffraction_loss(d,f,h_tx,h_rx,E_R);
 Lt = L_bfsg + abs(L_ctt)- E_sp + L_diff;
 [Lt,d, f, d_fs];
 L = Lt;
end

function G_dB = fss_filter_gain(f_MHz,guardInterval,attenuation,disable)
 if(disable == 1) G_dB = 0; return; end
 f_pass_lo = 3800 + guardInterval;
 f_pass_hi = 4200;
 f_stop_lo = 3600 + guardInterval;
 f_stop_hi = 4400;

 Astop = attenuation; % dB
 G_dB = zeros(size(f_MHz));
 idx = f_MHz <= f_stop_lo;
 G_dB(idx) = -Astop;
 idx = (f_MHz > f_stop_lo) & (f_MHz < f_pass_lo);
 x = (f_MHz(idx) - f_stop_lo) / (f_pass_lo - f_stop_lo);
 H = 0.5 * (1 - cos(pi*x));
 G_dB(idx) = 20*log10(H);
 G_dB(idx) = max(G_dB(idx), -Astop);
 idx = (f_MHz >= f_pass_lo) & (f_MHz <= f_pass_hi);
 G_dB(idx) = 0;
 idx = (f_MHz > f_pass_hi) & (f_MHz < f_stop_hi);
 x = (f_stop_hi - f_MHz(idx)) / (f_stop_hi - f_pass_hi);
 H = 0.5 * (1 - cos(pi*x));
 G_dB(idx) = 20*log10(H);
 G_dB(idx) = max(G_dB(idx), -Astop);
 idx = f_MHz >= f_stop_hi;
 G_dB(idx) = -Astop;
end

function Ld = diffraction_loss(d,f,h_tx,h_rx,E_R)
 if(d < radioHorison(h_tx,h_rx,E_R)) Ld = 0; return; end
 Re = E_R*1000*4/3;
 d_m = d*1000;
 lambda = 3e8/(f*1e9);
 h_bulge = d_m.^2/(8*Re);
 h_los = (h_tx+h_rx)/2;
 clearance = h_los - h_bulge;
 nu = -clearance .* sqrt(2./(lambda*d_m));
 Ld = zeros(size(d));
 idx = nu > -0.78;
 Ld(idx) = 6.9 + 20*log10(sqrt((nu(idx)-0.1).^2+1) + nu(idx)-0.1 );
 Ld(Ld<0)=0;
end

